<template>
  <div>
    <el-table
      ref="notestable"
      v-loading="loading"
      :data="tmpData"
      @selection-change="checkChange"
    >
      <el-table-column
        type="selection"
        width="55"
        :selectable="whereDisable"
      />
      
      <el-table-column
        prop="comment_id"
        label="id"
        width="100"
      />
      
      <el-table-column
        prop="content"
        label="評論內容"
      />

      <el-table-column
        prop="status_text"
        label="評論狀態"
      />

      <el-table-column
        label="創建人"
      >
        <template
          slot-scope="scope"
        >
          <div v-if="scope.row.userInfo">
            {{ scope.row.userInfo.nickanme }}</br>{{ scope.row.userInfo.mobile }}
          </div>
          <div v-else>
            管理員
          </div>
        </template>
      </el-table-column>

      <el-table-column
        prop="created_text"
        label="評論時間"
      />

      <el-table-column
        v-if="handleType"
        label="操作"
        width="160"
        align="center"
      >
        <template
          slot-scope="scope"
        >
          <div class="operating-icons">
            <el-button
              type="text"
              @click="viewDetails(scope.row, scope.$index)"
            >
              詳情
            </el-button>

            <el-button
              type="text"
              @click="auditNote(scope.row)"
            >
              {{ resetText(scope.row) }}
            </el-button>
          </div>
        </template>
      </el-table-column>
    </el-table>
  </div>
</template>

<script>
export default {
  props: {
    tmpData: Array,
    handleType:String,
    loading:Boolean
  },
  data () {
    return {

    }
  },
  computed: {
    resetText (){
      return (row)=>{
        var text = '審核';
        if(row.status=='1'){
          text = '拒絕'
        }else if(row.status=='2'){
          text = '通過'
        }
        return text;
      }
    }
  },
  mounted () {
  },
  methods: {
    whereDisable (row){
      var disable = true;
      // if(row.status=='1'){
      //   disable = false;
      // }
      //console.log('row',row)
      return disable;
    },
    viewDetails (row){
      this.$refs.notestable.clearSelection();
      this.$refs.notestable.toggleRowSelection(row);
      this.$emit('viewDetails',row.comment_id)
    },
    auditNote (row){
      var params = {
        id_set:[row.comment_id],
        auditdiff:false,
        aloneAuditType:row.status=='1'?'refuse':'pass'
      }
      this.$refs.notestable.clearSelection();
      this.$refs.notestable.toggleRowSelection(row);
      this.$emit('selectNotes',params)
    },
    checkChange (val){
      var checkList = [];
      var auditdiff = false;
      var status = null;

      val.forEach(item=>{
        checkList.push(item.comment_id);
        if(status==null){
          status = item.status;
        }else if(status!=item.status){
          auditdiff = true;
        }
      })

      var params = {
        id_set:checkList,
        auditdiff
      }

      this.$emit('selectNotes',params)
     //console.log('checkChange',checkList,auditdiff)
    }

  }
}
</script>
<style scoped lang="css">
.el-button + .el-button{margin-left: 20px;}
</style>
